import{_ as a,a as i,b as l}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"المصادقة وإدارة أجهزة تسجيل الدخول","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Safety/authentication-and-login-devices.md","filePath":"ar-SA/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),c={name:"ar-SA/Safety/authentication-and-login-devices.md"};function d(p,e,h,s,u,m){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="المصادقة-وإدارة-أجهزة-تسجيل-الدخول" tabindex="-1">المصادقة وإدارة أجهزة تسجيل الدخول <a class="header-anchor" href="#المصادقة-وإدارة-أجهزة-تسجيل-الدخول" aria-label="Permalink to &quot;المصادقة وإدارة أجهزة تسجيل الدخول&quot;">​</a></h1><p>تحمي <code>Authentication Management</code> و <code>Login Device Management</code> لوحة إدارة ImgBed، ومدخل الرفع العام، ووصول WebDAV.</p><p>استخدم هذه الصفحة لضبط بيانات الوصول، ومراجعة الأجهزة التي سجّلت الدخول، وإلغاء الجلسات القديمة عند الحاجة.</p><h2 id="أين-تضبطها؟" tabindex="-1">أين تضبطها؟ <a class="header-anchor" href="#أين-تضبطها؟" aria-label="Permalink to &quot;أين تضبطها؟&quot;">​</a></h2><p>افتح لوحة الإدارة، ثم انتقل إلى:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>تحتوي الصفحة على منطقتين رئيسيتين:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+a+'" alt="إدارة المصادقة" loading="lazy"></p><h2 id="ماذا-تفعل-authentication-management؟" tabindex="-1">ماذا تفعل Authentication Management؟ <a class="header-anchor" href="#ماذا-تفعل-authentication-management؟" aria-label="Permalink to &quot;ماذا تفعل Authentication Management؟&quot;">​</a></h2><p>تحفظ Authentication Management بيانات الوصول.</p><p>هناك نوعان:</p><ul><li>مصادقة جهة المستخدم</li><li>مصادقة جهة الإدارة</li></ul><h2 id="مصادقة-جهة-المستخدم" tabindex="-1">مصادقة جهة المستخدم <a class="header-anchor" href="#مصادقة-جهة-المستخدم" aria-label="Permalink to &quot;مصادقة جهة المستخدم&quot;">​</a></h2><p>مصادقة جهة المستخدم هي كلمة مرور الرفع.</p><p>بعد ضبط كلمة مرور الرفع، يجب على الزوار العاديين إدخالها قبل استخدام صفحة الرفع. هذا مناسب إذا لم ترغب في جعل صفحة الرفع العامة مفتوحة للجميع.</p><p><img src="'+i+'" alt="صفحة دخول المستخدم" loading="lazy"></p><h3 id="ضبط-كلمة-مرور-الرفع" tabindex="-1">ضبط كلمة مرور الرفع <a class="header-anchor" href="#ضبط-كلمة-مرور-الرفع" aria-label="Permalink to &quot;ضبط كلمة مرور الرفع&quot;">​</a></h3><p>عند ضبط كلمة مرور الرفع:</p><ul><li>يجب على الزوار إدخال كلمة المرور قبل استخدام صفحة الرفع.</li><li>لا يتاح الرفع إلا بعد قبول كلمة المرور.</li><li>إذا كانت جلسات أجهزة المستخدم مفعلة، يسجل ImgBed ذلك الجهاز.</li></ul><p>تغيير كلمة مرور الرفع يلغي الجلسات القديمة لجهة المستخدم. يحتاج الزوار إلى إدخال كلمة المرور الجديدة مرة أخرى.</p><h2 id="مصادقة-جهة-الإدارة" tabindex="-1">مصادقة جهة الإدارة <a class="header-anchor" href="#مصادقة-جهة-الإدارة" aria-label="Permalink to &quot;مصادقة جهة الإدارة&quot;">​</a></h2><p>تستخدم مصادقة جهة الإدارة اسم مستخدم وكلمة مرور للمسؤول.</p><p>هذا يحمي لوحة الإدارة. في بيئات الإنتاج يُنصح دائمًا بضبطه.</p><p><img src="'+l+'" alt="صفحة دخول الإدارة" loading="lazy"></p><h3 id="ضبط-بيانات-المسؤول" tabindex="-1">ضبط بيانات المسؤول <a class="header-anchor" href="#ضبط-بيانات-المسؤول" aria-label="Permalink to &quot;ضبط بيانات المسؤول&quot;">​</a></h3><p>عند ضبط اسم مستخدم وكلمة مرور للمسؤول:</p><ul><li>يتطلب فتح لوحة الإدارة تسجيل دخول.</li><li>ينشئ تسجيل الدخول الناجح سجل جهاز إداري.</li><li>يمكنك مراجعة الأجهزة أو تنظيفها أو إجبارها على الخروج من Login Device Management.</li></ul><p>تغيير اسم مستخدم المسؤول أو كلمة المرور يلغي جلسات الإدارة القديمة. ستحتاج إلى تسجيل الدخول مرة أخرى.</p><h2 id="ماذا-تفعل-login-device-management؟" tabindex="-1">ماذا تفعل Login Device Management؟ <a class="header-anchor" href="#ماذا-تفعل-login-device-management؟" aria-label="Permalink to &quot;ماذا تفعل Login Device Management؟&quot;">​</a></h2><p>تعرض Login Device Management الأجهزة التي سجّلت الدخول.</p><p>تساعدك على معرفة:</p><ul><li>الأجهزة التي وصلت إلى لوحة الإدارة.</li><li>الأجهزة التي وصلت إلى صفحة الرفع من جهة المستخدم.</li><li>عملاء WebDAV الذين اتصلوا.</li><li>هل جلسة الجهاز ما زالت صالحة.</li><li>هل ينبغي إجبار الأجهزة القديمة على الخروج.</li></ul><p>تحتوي الصفحة على ثلاث تبويبات:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="أمان-ملفات-cookie-العام" tabindex="-1">أمان ملفات Cookie العام <a class="header-anchor" href="#أمان-ملفات-cookie-العام" aria-label="Permalink to &quot;أمان ملفات Cookie العام&quot;">​</a></h2><p>في أعلى Login Device Management يمكنك ضبط سلوك ملفات cookie العام.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>يتحكم في عدد الأيام التي تبقى فيها جلسة المستخدم نشطة.</p><p>مثلًا، إذا ضبطته على 14 يومًا، فلن يحتاج الزائر غالبًا إلى إدخال كلمة مرور الرفع مرة أخرى خلال 14 يومًا.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>يتحكم في عدد الأيام التي تبقى فيها جلسة المسؤول نشطة.</p><p>مثلًا، إذا ضبطته على 14 يومًا، فلن يحتاج المسؤول غالبًا إلى تسجيل الدخول مرة أخرى خلال 14 يومًا.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>عند تفعيل Secure mode، ترسل المتصفحات ملفات login cookies عبر HTTPS فقط.</p><p>فعّله في مواقع الإنتاج التي تعمل عبر HTTPS. لا تفعّله أثناء اختبار HTTP المحلي، وإلا قد ترى سلوكًا مثل &quot;تم تسجيل الدخول بنجاح، لكن تحديث الصفحة يخرجني&quot;.</p><h2 id="أجهزة-دخول-الإدارة" tabindex="-1">أجهزة دخول الإدارة <a class="header-anchor" href="#أجهزة-دخول-الإدارة" aria-label="Permalink to &quot;أجهزة دخول الإدارة&quot;">​</a></h2><p>يعرض تبويب Admin الأجهزة التي سجّلت الدخول إلى لوحة الإدارة.</p><p>لا تظهر سجلات الأجهزة إلا بعد ضبط بيانات الإدارة والدخول إلى لوحة الإدارة عبر صفحة تسجيل الدخول.</p><p>يمكن أن تعرض بطاقة الجهاز:</p><ul><li>معلومات الجهاز والمتصفح</li><li>IP أول دخول</li><li>IP آخر نشاط</li><li>وقت الدخول</li><li>وقت آخر نشاط</li><li>وقت انتهاء الصلاحية</li><li>الحالة الحالية</li></ul><p>إذا رأيت جهازًا غير معروف، استخدم <code>Force Offline</code> لإبطال جلسته.</p><h2 id="تنظيف-الأجهزة-القديمة" tabindex="-1">تنظيف الأجهزة القديمة <a class="header-anchor" href="#تنظيف-الأجهزة-القديمة" aria-label="Permalink to &quot;تنظيف الأجهزة القديمة&quot;">​</a></h2><p>يزيل <code>Clean Up Old Devices</code> سجلات الدخول القديمة في التبويب الحالي دفعة واحدة.</p><p>استخدمه إذا كنت تشك أن جلسات قديمة قد تكون ما زالت نشطة على أجهزة أخرى.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p>يبطل <code>Force Offline</code> جلسة جهاز واحد.</p><p>بعد إجبار الجهاز على الخروج:</p><ul><li>يجب على أجهزة الإدارة تسجيل الدخول مرة أخرى.</li><li>يجب على أجهزة المستخدم إدخال كلمة مرور الرفع مرة أخرى.</li><li>يجب على عملاء WebDAV المصادقة من جديد.</li></ul><p>يمكن أيضًا إزالة الأجهزة المنتهية أو غير الصالحة.</p><h2 id="تسجيل-الخروج-من-الجهاز-الحالي" tabindex="-1">تسجيل الخروج من الجهاز الحالي <a class="header-anchor" href="#تسجيل-الخروج-من-الجهاز-الحالي" aria-label="Permalink to &quot;تسجيل الخروج من الجهاز الحالي&quot;">​</a></h2><p>تُوسم بطاقة الجهاز الحالي بـ <code>Current Device</code>.</p><p>بعد الخروج من الجهاز الحالي:</p><ul><li>تنتهي جلسة الإدارة الحالية.</li><li>تنتهي جلسة المستخدم الحالية.</li></ul><p>ستحتاج إلى تسجيل الدخول مرة أخرى قبل متابعة استخدام تلك المنطقة.</p>',65)])])}const k=t(c,[["render",d]]);export{b as __pageData,k as default};
